mapper.select:
select s.*,
       c.name as clazz_name
from student s
         left join clazz c on s.clazz_id = c.id


        s.name like concat('%', #{name}, '%')


        and s.no like concat('%', #{no}, '%')


        and s.gender = #{gender}


        and s.degree = #{degree}


        and s.clazz_id = #{clazzId}


        and s.graduation_date between #{begin} and #{end}


order by s.id desc
